func solve(nums []int64, k int64) int64 {
    // We need to find the minimum possible sum after removing as many subarrays as possible
    // that have a sum divisible by k.
    // To do this, we can use a prefix sum approach with a hash map to track remainders.
    // We will keep track of the minimum sum that can be achieved for each remainder.
    // The final answer is the minimum sum among all remainders.

    // If k is 1, all elements can be removed, so the answer is 0.
    if k == 1 {
        return 0
    }

    // Initialize a map to store the minimum sum for each remainder.
    // The key is the remainder, the value is the minimum sum for that remainder.
    remainderMap := make(map[int64]int64)
    remainderMap[0] = 0 // The remainder 0 has a sum of 0 initially.

    // Initialize the prefix sum and the current sum.
    var prefixSum int64
    var minSum int64

    for _, num := range nums {
        prefixSum += num
        remainder := prefixSum % k

        // If the remainder is not in the map, add it with the current prefix sum.
        if _, exists := remainderMap[remainder]; !exists {
            remainderMap[remainder] = prefixSum
        } else {
            // Update the minimum sum for this remainder.
            if prefixSum < remainderMap[remainder] {
                remainderMap[remainder] = prefixSum
            }
        }

        // Update the overall minimum sum.
        if remainderMap[remainder] < minSum || minSum == 0 {
            minSum = remainderMap[remainder]
        }
    }

    // The answer is the minimum sum among all remainders.
    return minSum
}
