func solve(nums []int64, k int64) int64 {
    // Calculate the total sum of the array
    totalSum := int64(0)
    for _, num := range nums {
        totalSum += num
    }

    // If k is 1, all elements can be removed, so the minimum possible sum is 0
    if k == 1 {
        return 0
    }

    // Use a prefix sum array to track the cumulative sum modulo k
    prefixMod := make([]int64, len(nums)+1)
    for i := 0; i < len(nums); i++ {
        prefixMod[i+1] = (prefixMod[i] + nums[i]) % k
    }

    // Use a map to track the frequency of each prefix modulo
    modCount := make(map[int64]int64)
    for i := 0; i <= len(nums); i++ {
        modCount[prefixMod[i]]++
    }

    // The minimum possible sum is the total sum minus the maximum possible sum that can be removed
    // The maximum possible sum that can be removed is the maximum value of (count * k) where count is the frequency of a prefix modulo
    maxRemovable := int64(0)
    for mod, count := range modCount {
        if mod == 0 {
            // If the prefix modulo is 0, the entire subarray from start to current index can be removed
            maxRemovable = int64(maxRemovable, count*k)
        } else {
            // For other mod values, the maximum removable is (count * k)
            maxRemovable = int64(maxRemovable, count*k)
        }
    }

    return totalSum - maxRemovable
}
